import numpy as np
from typing import List, Dict

def decompose_to_clifford_t(gate_name: str, qubits: List[int]) -> List[Dict]:
    """
    Decompose a gate into Clifford+T gate set.
    """
    if gate_name == 'X':
        # X = HZH = H(SS)H
        q = qubits[0]
        return [
            {'name': 'H', 'qubits': [q]},
            {'name': 'S', 'qubits': [q]},
            {'name': 'S', 'qubits': [q]},
            {'name': 'H', 'qubits': [q]}
        ]

    elif gate_name == 'Y':
        # Y = SXS^dag = S(H S S H)S^dag
        q = qubits[0]
        return [
            {'name': 'S', 'qubits': [q]},
            {'name': 'H', 'qubits': [q]},
            {'name': 'S', 'qubits': [q]},
            {'name': 'S', 'qubits': [q]},
            {'name': 'H', 'qubits': [q]},
            {'name': 'S_dag', 'qubits': [q]}
        ]

    elif gate_name == 'Z':
        # Z = S * S (two phase gates)
        q = qubits[0]
        return [
            {'name': 'S', 'qubits': [q]},
            {'name': 'S', 'qubits': [q]}
        ]

    elif gate_name == 'CZ':
        # CZ = (I ⊗ H) CNOT (I ⊗ H)
        c, t = qubits
        return [
            {'name': 'H', 'qubits': [t]},
            {'name': 'CNOT', 'qubits': [c, t]},
            {'name': 'H', 'qubits': [t]}
        ]

    elif gate_name == 'SWAP':
        # SWAP = CNOT(a,b) CNOT(b,a) CNOT(a,b)
        a, b = qubits
        return [
            {'name': 'CNOT', 'qubits': [a, b]},
            {'name': 'CNOT', 'qubits': [b, a]},
            {'name': 'CNOT', 'qubits': [a, b]}
        ]

    else:
        raise ValueError(f"Unknown gate: {gate_name}")

# Test
test_cases = [
    ('X', [0]),
    ('Y', [0]),
    ('Z', [0]),
    ('CZ', [0, 1]),
    ('SWAP', [0, 1])
]

for gate, qubits in test_cases:
    result = decompose_to_clifford_t(gate, qubits)
    print(f"{gate} on {qubits}: {len(result)} gates")
    print(f"  Decomposition: {[g['name'] for g in result]}")
